package com.schoolbus.controller;
import com.schoolbus.dto.request.*;import com.schoolbus.dto.response.*;import com.schoolbus.service.AdminCrudService;import jakarta.validation.Valid;import org.springframework.data.domain.*;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/admin/drivers") public class AdminDriverController{private final AdminCrudService s;public AdminDriverController(AdminCrudService s){this.s=s;}@GetMapping public ApiResponse<PageResponse<DriverResponse>> list(@RequestParam(required=false)String search,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.success(PageResponse.from(s.drivers(search,PageRequest.of(page,size))));}@GetMapping("/{id}")public ApiResponse<DriverResponse> get(@PathVariable Long id){return ApiResponse.success(s.driver(id));}@PostMapping public ResponseEntity<ApiResponse<DriverResponse>> create(@Valid @RequestBody DriverRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success("Driver created",s.createDriver(r)));}@PutMapping("/{id}")public ApiResponse<DriverResponse> update(@PathVariable Long id,@Valid @RequestBody DriverRequest r){return ApiResponse.success(s.updateDriver(id,r));}@PatchMapping("/{id}/deactivate")public ApiResponse<Void> deactivate(@PathVariable Long id){s.deactivateDriver(id);return ApiResponse.success("Driver deactivated",null);}}
